sparql:
SELECT(MIN(YEAR(?startYear)) AS ?firstYear) WHERE {
  ?team wdt:P276 wd:Q206337 .
  ?team wdt:P1328 ?season .
  ?season wdt:P585 ?startYear .
  ?season wdt:P1453 wd:Q2523727 .
}

SELECT ?area WHERE {
  wd:Q183 wdt:P2046 ?area
}

SELECT ?teamLabel WHERE {
  wd:Q1281 rdfs:label ?teamLabel .
  FILTER(lang(?teamLabel) = "en")
}

SELECT ?population WHERE {
  wd:Q65 wdt:P1082 ?population .
}

SELECT ?population WHERE {
  wd:Q55 wdt:P1082 ?population .
}

SELECT(?republicans - ?democrats AS ?diff) WHERE {
  {
    SELECT(COUNT(?rep) AS ?republicans) WHERE {
      wd:Q1670187 p:P1733 ?membership .
      ?membership ps:P1733 ?rep .
      ?rep wdt:P102 wd:Q2006338 .
    }
  }
  {
    SELECT(COUNT(?dem) AS ?democrats) WHERE {
      wd:Q1670187 p:P1733 ?membership .
      ?membership ps:P1733 ?dem .
      ?dem wdt:P102 wd:Q174409 .
    }
  }
}

SELECT ?areaLabel WHERE {
  wd:Q186828 rdfs:label ?areaLabel .
  FILTER(LANG(?areaLabel) = 'en')
}

SELECT ?event WHERE {
  ?event rdfs:label 'hammer throw' @en
}

SELECT ?mayor ?mayorLabel WHERE {
  wd:Q44498 wdt:P6 ?mayor .
  ?mayor rdfs:label ?mayorLabel .
  FILTER(LANG(?mayorLabel) = "en")
}

SELECT ?population WHERE {
  wd:Q22538 p:P1082 ?populationStatement .
  ?populationStatement ps:P1082 ?population ; pq:P585 ?time .
  FILTER(year(?time) = 1975)
}

SELECT ?population WHERE {
  wd:Q30 wdt:P36 ?capital .
  ?capital wdt:P1082 ?population .
}

SELECT(COUNT(?state) AS ?count) WHERE {
  ?state wdt:P31 wd:Q109556 ; wdt:P17 wd:Q155 .
}

SELECT ?event WHERE {
  ?event rdfs:label "1967 European Indoor Games" @en .
}

SELECT ?sea WHERE {
  wd:Q355 rdfs:label ?sea .
  FILTER(LANG(?sea) = 'en')
}

SELECT(COUNT(DISTINCT ?event) AS ?count) WHERE {
  ?fireEvent wdt:P31 wd:Q7198 ; wdt:P571 ?fireDate ; wdt:P1798 ?venue .
  FILTER(YEAR(?fireDate) = 1991)
  ?event wdt:P21 wd:Q6581097 ; wdt:P1142 ?venue ; wdt:P585 ?eventDate ; wdt:P1630 wd:Q8903 .
  FILTER(YEAR(?eventDate) = 1956)
}

SELECT(COUNT(DISTINCT ?olympic) AS ?count) WHERE {
  wd:Q2700064 p:P534 ?participant .
  ?participant ps:P534 ?athlete .
  ?athlete wdt:P27 wd:Q78 .
  ?athlete p:P198 ?olympicStatement ; ps:P198 ?olympic .
}

SELECT ?championship WHERE {
  ?championship rdfs:label "Meath Senior Football Championship" @en .
}

SELECT(YEAR(?date) AS ?year) WHERE {
  wd:Q151 wdt:P571 ?date
}

SELECT ?label WHERE {
  wd:Q258975 rdfs:label ?label .
}

SELECT(SUM(?population) AS ?total) WHERE {
  ?protectedArea wdt:P31 wd:Q1909625 ; wdt:P131 ?province .
  ?province wdt:P31 wd:Q1086 ; wdt:P131 wd:Q291911 ; wdt:P1082 ?population .
}
